// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.benchmark;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.Arrays;

import org.eclipse.rdf4j.query.explanation.Explanation;
import org.junit.jupiter.api.Test;
import org.openjdk.jmh.annotations.Param;

class ThemeQueryBenchmarkExplanationTest {

	@Test
	void defaultQueryExplanationLevelIsTimed() throws Exception {
		Param param = ThemeQueryBenchmark.class.getField("queryExplanationLevel").getAnnotation(Param.class);

		assertTrue(Arrays.asList(param.value()).contains(Explanation.Level.Timed.name()),
				"ThemeQueryBenchmark should default non-timeout benchmark explanations to Timed");
	}

	@Test
	void benchmarkExplanationLevelArgumentIsParsedCaseInsensitively() throws Exception {
		var method = ThemeQueryBenchmark.class.getDeclaredMethod("explanationLevel", String.class);
		method.setAccessible(true);

		assertEquals(Explanation.Level.Telemetry, method.invoke(null, "telemetry"),
				"ThemeQueryBenchmark should accept case-insensitive explanation level arguments");
	}

	@Test
	void timedOutBenchmarkUsesOptimizedExplanation() throws Exception {
		var benchmark = new ThemeQueryBenchmark();
		var field = ThemeQueryBenchmark.class.getField("queryExplanationLevel");
		field.set(benchmark, Explanation.Level.Telemetry.name());
		var method = ThemeQueryBenchmark.class.getDeclaredMethod("benchmarkExplanationLevel", boolean.class);
		method.setAccessible(true);

		assertEquals(Explanation.Level.Optimized, method.invoke(benchmark, true),
				"Timed-out benchmark executions should explain the optimized plan");
		assertEquals(Explanation.Level.Telemetry, method.invoke(benchmark, false),
				"Non-timeout benchmark executions should use the configured explanation level");
	}
}
